INSERT INTO IELTSExam (id, title, type, totalQuestions) VALUES (191, '剑桥雅思 19 - Test 1 阅读', 'reading', 40);
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1910, 191, 1, 'Passage 1: How tennis rackets have changed', 'In 2016, the British professional tennis player Andy Murray was ranked as the world\'s number one. It was an incredible achievement by any standard – made even more remarkable by the fact that he did this during a period considered to be one of the strongest in the sport\'s history, competing against the likes of Rafael Nadal, Roger Federer and Novak Djokovic, to name just a  few. Yet five years previously, he had been regarded as a talented outsider who entered but never won the major tournaments.\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (179, 1910, 1, 'true_false', 'People had expected Andy Murray to become the world\'s top tennis player for at least five years before 2016.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (180, 1910, 2, 'true_false', 'The change that Andy Murray made to his rackets attracted a lot of attention.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (181, 1910, 3, 'true_false', 'Most of the world\'s top players take a professional racket stringer on tour with them.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (182, 1910, 4, 'true_false', 'Mike and Bob Bryan use rackets that are light in comparison to the majority of rackets.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (183, 1910, 5, 'true_false', 'Werner Fischer played with a spaghetti-strung racket that he designed himself.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (184, 1910, 6, 'true_false', 'The weather can affect how professional players adjust the strings on their rackets.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (185, 1910, 7, 'true_false', 'It was believed that the change Pete Sampras made to his rackets contributed to his strong serve.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (186, 1910, 8, 'fill_blank', '·Mike and Bob Bryan made changes to the types of ______ used on their racket frames.', '## The tennis racket and how it has changed\n\n·Mike and Bob Bryan made changes to the types of (8) ______ used on their racket frames.\n·Players were not allowed to use the spaghetti-strung racket because of the amount of (9) ______ it created.\n·Changes to rackets can be regarded as being as important as players\' diets or the (10) ______ they do.\n·All rackets used to have natural strings made from the (11) ______ of animals.\n·Pete Sampras had metal (12) ______ put into the frames of his rackets.\n·Gonçalo Oliveira changed the (13) ______ on his racket handles.', NULL, 'paint');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (187, 1910, 9, 'fill_blank', '·Players were not allowed to use the spaghetti-strung racket because of the amount of ______ it created.', NULL, NULL, 'topspin');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (188, 1910, 10, 'fill_blank', '·Changes to rackets can be regarded as being as important as players\' diets or the ______ they do.', NULL, NULL, 'training');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (189, 1910, 11, 'fill_blank', '·All rackets used to have natural strings made from the ______ of animals.', NULL, NULL, 'intestines|gut');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (190, 1910, 12, 'fill_blank', '·Pete Sampras had metal ______ put into the frames of his rackets.', NULL, NULL, 'weights');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (191, 1910, 13, 'fill_blank', '·Gonçalo Oliveira changed the ______ on his racket handles.', NULL, NULL, 'grips');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1920, 191, 2, 'Passage 2: The pirates of the ancient Mediterranean', 'In the first and second millennia BCE, pirates sailed around the Mediterranean, attacking ships and avoiding pursuers\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (192, 1920, 14, 'matching', 'a reference to a denial of involvement in piracy', NULL, '["A","B","C","D","E","F","G"]', 'D');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (193, 1920, 15, 'matching', 'details of how a campaign to eradicate piracy was carried out', NULL, '["A","B","C","D","E","F","G"]', 'G');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (194, 1920, 16, 'matching', 'a mention of the circumstances in which states in the ancient world would make use of pirates', NULL, '["A","B","C","D","E","F","G"]', 'C');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (195, 1920, 17, 'matching', 'a reference to how people today commonly view pirates', NULL, '["A","B","C","D","E","F","G"]', 'A');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (196, 1920, 18, 'matching', 'an explanation of how some people were encouraged not to return to piracy', NULL, '["A","B","C","D","E","F","G"]', 'G');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (197, 1920, 19, 'matching', 'a mention of the need for many sailing vessels to stay relatively close to land', NULL, '["A","B","C","D","E","F","G"]', 'B');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (198, 1920, 20, 'multiple_choice', 'Which **TWO** of the following statements does the writer make about inhabitants of the Mediterranean region in the ancient world?', NULL, '["A. They often used stolen vessels to carry out pirate attacks.","B. They managed to escape capture by the authorities because they knew the area so well.","C. They paid for information about the routes merchant ships would take.","D. They depended more on the sea for their livelihood than on farming.","E. They stored many of the goods taken in pirate attacks in coves along the coastline."]', 'B. They managed to escape capture by the authorities because they knew the area so well.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (199, 1920, 21, 'multiple_choice', 'Which **TWO** of the following statements does the writer make about inhabitants of the Mediterranean region in the ancient world?', NULL, '["A. They often used stolen vessels to carry out pirate attacks.","B. They managed to escape capture by the authorities because they knew the area so well.","C. They paid for information about the routes merchant ships would take.","D. They depended more on the sea for their livelihood than on farming.","E. They stored many of the goods taken in pirate attacks in coves along the coastline."]', 'D. They depended more on the sea for their livelihood than on farming.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (200, 1920, 22, 'multiple_choice', 'Which ** TWO ** of the following statements does the writer make about piracy and ancient Greece?', NULL, '["A. The state estimated that very few people were involved in piracy.","B. Attitudes towards piracy changed shortly after the Iliad and the Odyssey were written.","C. Important officials were known to occasionally take part in piracy.","D. Every citizen regarded pirate attacks on cities as unacceptable.","E. A favourable view of piracy is evident in certain ancient Greek texts."]', 'C. Important officials were known to occasionally take part in piracy.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (201, 1920, 23, 'multiple_choice', 'Which ** TWO ** of the following statements does the writer make about piracy and ancient Greece?', NULL, '["A. The state estimated that very few people were involved in piracy.","B. Attitudes towards piracy changed shortly after the Iliad and the Odyssey were written.","C. Important officials were known to occasionally take part in piracy.","D. Every citizen regarded pirate attacks on cities as unacceptable.","E. A favourable view of piracy is evident in certain ancient Greek texts."]', 'E. A favourable view of piracy is evident in certain ancient Greek texts.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (202, 1920, 24, 'fill_blank', 'However, attacks on vessels transporting ______ to Rome resulted in calls for ______ for the pirates responsible. Nevertheless, piracy continued, with some pirates demanding a ______ for the return of the Roman officials they captured.', '## Ancient Rome and piracy\n\nPiracy was an issue ancient Rome had to deal with, but it also brought some benefits for Rome. For example, pirates supplied slaves that were important for Rome\'s industries.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (203, 1920, 25, 'fill_blank', 'However, attacks on vessels transporting ______ to Rome resulted in calls for ______ for the pirates responsible. Nevertheless, piracy continued, with some pirates demanding a ______ for the return of the Roman officials they captured.', NULL, NULL, 'punishment');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (204, 1920, 26, 'fill_blank', 'However, attacks on vessels transporting ______ to Rome resulted in calls for ______ for the pirates responsible. Nevertheless, piracy continued, with some pirates demanding a ______ for the return of the Roman officials they captured.', NULL, NULL, 'ransom');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1930, 191, 3, 'Passage 3: The persistence and peril of misinformation', 'Brian Southwell looks at how human brains verify information and discusses some of the challenges of battling widespread falsehoods\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (205, 1930, 27, 'multiple_choice', 'What point does the writer make about misinformation in the first paragraph?', NULL, '["A. Misinformation is a relatively recent phenomenon","B. Some people find it easy to identify misinformation","C. Misinformation changes as it is passed from one person to another","D. There may be a number of reasons for the spread of misinformation"]', 'There may be a number of reasons for the spread of misinformation.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (206, 1930, 28, 'multiple_choice', 'What does the writer say about the role of technology?', NULL, '["A. It may at some point provide us with a solution to misinformation","B. It could fundamentally alter the way in which people regard information","C. It has changed the way in which organisations use misinformation","D. It has made it easier for people to check whether information is accurate"]', 'It may at some point provide us with a solution to misinformation.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (207, 1930, 29, 'multiple_choice', 'What is the writer doing in the fourth paragraph?', NULL, '["A. comparing the different opinions people have of misinformation","B. explaining how the effects of misinformation have changed over time","C. outlining which issues connected with misinformation are significant today","D. describing the attitude of policy makers towards misinformation in the media"]', 'outlining which issues connected with misinformation are significant today');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (208, 1930, 30, 'multiple_choice', 'What point does the writer make about regulation in the USA?', NULL, '["A. The guidelines issued by the FDA need to be simplified","B. Regulation does not affect people\'s opinions of new prescription drugs","C. The USA has more regulatory bodies than most other countries","D. Regulation fails to prevent misinformation from appearing in the media"]', 'Regulation fails to prevent misinformation from appearing in the media.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (209, 1930, 31, 'matching', 'Speech translation methods are developing fast in Japan', 'Although people have to misinformation, there is debate about precisely how and when we label something as true or untrue. The philosophers Descartes and Spinoza had about how people engage with information. While Descartes believed that people accept or reject information after considering whether it is true or not, Spinoza argued that people accepted all information they encountered (and by default misinformation) and did not verify or reject it until afterwards. Moreover, Spinoza believed that a distinct is involved in these stages. Recent research has provided for Spinoza\'s theory and it would appear that people accept all encountered information as if it were true, even if this is for an extremely , and do not label the information as true or false until later. This is consistent with the fact that the resources for scepticism and the resources for perceiving and encoding are in in the brain.', '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'frequent exposure');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (210, 1930, 32, 'matching', 'TV interviews that use translation voice over methods are successful', NULL, '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'different ideas');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (211, 1930, 33, 'matching', 'Many people who ended up winning prestigious intellectual prizes only reached an average standard when young.', NULL, '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'mental operation');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (212, 1930, 34, 'matching', 'Einstein\'s failures as a young man were due to his lack of confidence.', NULL, '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'additional evidence');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (213, 1930, 35, 'matching', 'Language translation systems will be seen as very useful throughout the academic and professional worlds.', NULL, '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'short period');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (214, 1930, 36, 'matching', 'Some anthropologists are mistaken about the point when the number of societies such as the !Kung began to decline.', NULL, '["constant conflict","additional evidence","different locations","experimental subjects","short period","extreme distrust","frequent exposure","mental operation","dubious reason","different ideas"]', 'different locations');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (215, 1930, 37, 'true_false', 'Campaigns designed to correct misinformation will fail to achieve their purpose if people are unable to understand them.', NULL, NULL, 'YES');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (216, 1930, 38, 'true_false', 'Attempts to teach elementary school students about misinformation have been opposed.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (217, 1930, 39, 'true_false', 'It may be possible to overcome the problem of misinformation in a relatively short period.', NULL, NULL, 'NO');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (218, 1930, 40, 'true_false', 'The need to keep up with new information is hugely exaggerated in today\'s world.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSExam (id, title, type, totalQuestions) VALUES (192, '剑桥雅思 19 - Test 2 阅读', 'reading', 40);
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1921, 192, 1, 'Passage 1: The Industrial Revolution in Britain', 'The Industrial Revolution began in Britain in the mid-1700s and by the 1830s and 1840s had spread to many other parts of the world, including the United States. In Britain, it was a period when a largely rural, agrarian* society was transformed into an industrialised, urban one. Goods that had once been crafted by hand started to be produced in mass quantities  by machines in factories, thanks to the invention of steam power and the introduction of new machines and manufacturing techniques in textiles, iron-making and other industries.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (219, 1921, 1, 'fill_blank', '● In Watt and Boulton\'s steam engine, the movement of the ______ was linked to a gear system.', '## Britain\'s Industrial Revolution\n\nSteam power\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (220, 1921, 2, 'fill_blank', '● A greater supply of ______ was required to power steam engines.', NULL, NULL, 'coal');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (221, 1921, 3, 'fill_blank', '● Before the Industrial Revolution, spinners and weavers worked at home and in ______ .', NULL, NULL, 'workshops');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (222, 1921, 4, 'fill_blank', '● Not as much ______ was needed to produce cloth once the spinning jenny and power loom were invented.', NULL, NULL, 'labour|labor');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (223, 1921, 5, 'fill_blank', '● Smelting of iron ore with coke resulted in material that was better ______ .', NULL, NULL, 'quality');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (224, 1921, 6, 'fill_blank', '● Demand for iron increased with the growth of the ______', NULL, NULL, 'railways|railway');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (225, 1921, 7, 'fill_blank', '● The new cities were dirty, crowded and lacked sufficient ______ .', NULL, NULL, 'sanitation');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (226, 1921, 8, 'true_false', 'Britain\'s canal network grew rapidly so that more goods could be transported around the country.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (227, 1921, 9, 'true_false', 'Costs in the iron industry rose when the technique of smelting iron ore with coke was introduced.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (228, 1921, 10, 'true_false', 'Samuel Morse\'s communication system was more reliable than that developed by William Cooke and Charles Wheatstone.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (229, 1921, 11, 'true_false', 'The economic benefits of industrialisation were limited to certain sectors of society.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (230, 1921, 12, 'true_false', 'Some skilled weavers believed that the introduction of the new textile machines would lead to job losses.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (231, 1921, 13, 'true_false', 'There was some sympathy among local people for the Luddites who were arrested near Huddersfield.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1922, 192, 2, 'Passage 2: Athletes and stress', 'A\nIt isn\'t easy being a professional athlete. Not only are the physical demands greater than most people could handle, athletes also face intense psychological pressure during competition. This is something that British tennis player Emma Raducanu wrote about on social media following her withdrawal from the 2021 Wimbledon tournament. Though the young player had been doing well in the tournament, she began having difficulty regulating her breathing and heart rate during a match, which she later attributed to \'the accumulation of the excitement and the buzz\'.INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (232, 1922, 14, 'matching', 'reference to two chemical compounds which impact on performance', NULL, '["A","B","C","D","E","F"]', 'D');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (233, 1922, 15, 'matching', 'examples of strategies for minimising the effects of stress', NULL, '["A","B","C","D","E","F"]', 'F');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (234, 1922, 16, 'matching', 'how a sportsperson accounted for their own experience of stress', NULL, '["A","B","C","D","E","F"]', 'A');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (235, 1922, 17, 'matching', 'study results indicating links between stress responses and performance', NULL, '["A","B","C","D","E","F"]', 'C');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (236, 1922, 18, 'matching', 'mention of people who can influence how athletes perceive their stress responses', NULL, '["A","B","C","D","E","F"]', 'F');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (237, 1922, 19, 'fill_blank', 'Performance stress involves many demands on the athlete, for example, coping with the possible risk of ______.', 'Performance stress involves many demands on the athlete, for example, coping with the possible risk of (19) ______.\n\nCortisol can cause tennis players to produce fewer good (20) ______.\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (238, 1922, 20, 'fill_blank', 'Cortisol can cause tennis players to produce fewer good ______.', NULL, NULL, 'serves');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (239, 1922, 21, 'fill_blank', 'Psychologists can help athletes to view their physiological responses as the effect of a positive feeling such as ______.', NULL, NULL, 'excitement');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (240, 1922, 22, 'fill_blank', '______ is an example of a psychological technique which can reduce an athlete\'s stress responses.', NULL, NULL, 'visualisation|visualization');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (241, 1922, 23, 'multiple_choice', 'Which **TWO** facts about Emma Raducanu\'s withdrawal from the Wimbledon tournament are mentioned in the text?', NULL, '["A. the stage at which she dropped out of the tournament","B. symptoms of her performance stress at the tournament","C. measures which she had taken to manage her stress levels","D. aspects of the Wimbledon tournament which increased her stress levels","E. reactions to her social media posts about her experience at Wimbledon"]', 'B. symptoms of her performance stress at the tournament');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (242, 1922, 24, 'multiple_choice', 'Official policies towards wetlands vary from one nation to the next.', NULL, '["A. the stage at which she dropped out of the tournament","B. symptoms of her performance stress at the tournament","C. measures which she had taken to manage her stress levels","D. aspects of the Wimbledon tournament which increased her stress levels","E. reactions to her social media posts about her experience at Wimbledon"]', 'D. aspects of the Wimbledon tournament which increased her stress levels');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (243, 1922, 25, 'multiple_choice', 'Which **TWO** facts about anxiety are mentioned in Paragraph E of the text?', NULL, '["A. the factors which determine how severe it may be","B. how long it takes for its effects to become apparent","C. which of its symptoms is most frequently encountered","D. the types of athletes who are most likely to suffer from it","E. the harm that can result if athletes experience it too often"]', 'A. the factors which determine how severe it may be');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (244, 1922, 26, 'multiple_choice', 'Initiatives to reverse environmental damage need not be complex.', NULL, '["A. the factors which determine how severe it may be","B. how long it takes for its effects to become apparent","C. which of its symptoms is most frequently encountered","D. the types of athletes who are most likely to suffer from it","E. the harm that can result if athletes experience it too often"]', 'E. the harm that can result if athletes experience it too often');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1923, 192, 3, 'Passage 3: An inquiry into the existence of the gifted child', 'Let us start by looking at a modern \'genius\', Maryam Mirzakhani, who died at the early age of 40. She was the only woman to win the Fields Medal – the mathematical equivalent of a Nobel prize. It would be easy to assume that someone as special as Mirzakhani must have been one of those \'gifted\' children, those who have an extraordinary ability in a specific sphere of activity or knowledge. But look closer and a different story emerges. Mirzakhani was born in Tehran, Iran. She went to a highly selective girls\' school but maths wasn\'t her interest – reading was. She loved novels and would read anything she could lay her hands on. As for maths, she did rather poorly at it for the first couple of years in her middle school, but became interested when her elder brother told her about what he\'d learned. He shared a famous maths problem from a magazine that fascinated her – and she was hooked.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (245, 1923, 27, 'matching', 'an example of how one predator has been protected by the introduction of livestock guard dogs', 'Maryam Mirzakhani is regarded as in the field of mathematics because she was the only female holder of the prestigious Fields Medal –a record that she retained at the time of her death. However, maths held little for her as a child and in fact her performance was below average until she was by a difficult puzzle that one of her siblings showed her. Later, as a professional mathematician, she had an inquiring mind and proved herself to be when things did not go smoothly. She said she got the greatest from making ground-breaking discoveries and in fact she was responsible for some extremely mathematical studies.', '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'unique');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (246, 1923, 28, 'matching', 'an optimistic suggestion about the possible positive developments in the use of livestock guard dogs', NULL, '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'appeal');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (247, 1923, 29, 'matching', 'a description of how the methods used by livestock guard dogs help to keep predators away', NULL, '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'intrigued');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (248, 1923, 30, 'matching', 'claims by different academics that the use of livestock guard dogs is a successful way of protecting farmers\' herds', NULL, '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'determined');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (249, 1923, 31, 'matching', 'a reference to how livestock guard dogs gain their skills', NULL, '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'satisfaction');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (250, 1923, 32, 'matching', 'The use of guard dogs may save the lives of both livestock and wild animals.', NULL, '["appeal","determined","intrigued","single","achievement","devoted","involved","unique","innovative","satisfaction","intent"]', 'innovative');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (251, 1923, 33, 'true_false', 'Many people who ended up winning prestigious intellectual prizes only reached an average standard when young.', NULL, NULL, 'YES');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (252, 1923, 34, 'true_false', 'Einstein\'s failures as a young man were due to his lack of confidence.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (253, 1923, 35, 'true_false', 'It is difficult to reach agreement on whether some children are actually born gifted.', NULL, NULL, 'YES');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (254, 1923, 36, 'true_false', 'Einstein was upset by the public\'s view of his life\'s work.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (255, 1923, 37, 'true_false', 'Einstein put his success down to the speed at which he dealt with scientific questions.', NULL, NULL, 'NO');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (256, 1923, 38, 'multiple_choice', 'What does Eyre believe is needed for children to equal \'gifted\' standards?', NULL, '["Higher IQ scores","Special schools","A spirit of inquiry and hard work","Less homework"]', 'the development of a spirit of inquiry towards their studies');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (257, 1923, 39, 'multiple_choice', 'What is the result of Ericsson\'s research?', NULL, '["Innate talent is essential","Innate talents are not central to success","Children should be tested early","Genius is entirely genetic"]', 'Being born with a special gift is not the key factor in becoming expert.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (258, 1923, 40, 'multiple_choice', 'In the penultimate paragraph, it is stated the key to some deprived children\'s success is', NULL, '["Financial support","Access to technology","Better nutrition","Guidance from adults who value learning"]', 'the guidance of someone who recognises the benefits of learning.');
INSERT INTO IELTSExam (id, title, type, totalQuestions) VALUES (193, '剑桥雅思 19 - Test 3 阅读', 'reading', 40);
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1931, 193, 1, 'Passage 1: Archaeologists discover evidence of prehistoric island settlers', 'In early April 2019, Dr Ceri Shipton and his colleagues from Australian National University became the first archaeologists to explore Obi, one of many tropical islands in Indonesia\'s Maluku Utara province. The research team\'s discoveries suggest that the prehistoric people who lived on Obi were adept on both land and sea, hunting in the dense rainforest, foraging on the seashore, and possibly even voyaging between islands.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (259, 1931, 1, 'true_false', 'Archaeological research had taken place on the island of Obi before the arrival of Ceri Shipton and his colleagues.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (260, 1931, 2, 'true_false', 'At the Kelo sites, the researchers found the first clamshell axes ever to be discovered in the region.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (261, 1931, 3, 'true_false', 'The size of Obi today is less than it was 18,000 years ago.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (262, 1931, 4, 'true_false', 'A change in the climate around 11,700 years ago had a greater impact on Obi than on the surrounding islands.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (263, 1931, 5, 'true_false', 'The researchers believe there is a connection between warmer, wetter weather and a change in the material used to make axes.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (264, 1931, 6, 'true_false', 'Shipton\'s team were surprised to find evidence of the Obi islanders\' hunting practices.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (265, 1931, 7, 'true_false', 'It is thought that the Kelo shelters were occupied continuously until about 1,000 years ago.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (266, 1931, 8, 'fill_blank', '·Mike and Bob Bryan made changes to the types of ______ used on their racket frames.', '## Archaeological findings on Obi\n\nExcavations of rock shelters inside (8) ______ near the village of Kelo revealed:\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (267, 1931, 9, 'fill_blank', '·Players were not allowed to use the spaghetti-strung racket because of the amount of ______ it created.', NULL, NULL, 'stone');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (268, 1931, 10, 'fill_blank', '·Changes to rackets can be regarded as being as important as players\' diets or the ______ they do.', NULL, NULL, 'bones');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (269, 1931, 11, 'fill_blank', '·All rackets used to have natural strings made from the ______ of animals.', NULL, NULL, 'beads');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (270, 1931, 12, 'fill_blank', '·Pete Sampras had metal ______ put into the frames of his rackets.', NULL, NULL, 'pottery');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (271, 1931, 13, 'fill_blank', '·Gonçalo Oliveira changed the ______ on his racket handles.', NULL, NULL, 'spices');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1932, 193, 2, 'Passage 2: The global importance of wetlands', 'A\nWetlands are areas where water covers the soil, or is present either at or near the surface of the soil, for all or part of the year. These are complex ecosystems, rich in unique plant and animal life. But according to the World Wide Fund for Nature (WWFN), half of the world\'s wetlands have disappeared since 1990 – converted or destroyed for commercial development, drainage schemes and the extraction of minerals and peat*. Many of those that remain have been damaged by agricultural pesticides and fertilisers, industrial pollutants, and construction works.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (272, 1932, 14, 'matching', 'reference to the need to ensure that inhabitants of wetland regions continue to benefit from them', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'G');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (273, 1932, 15, 'matching', 'the proportion of wetlands which have already been lost', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'A');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (274, 1932, 16, 'matching', 'reference to the idea that people are beginning to appreciate the value of wetlands', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'H');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (275, 1932, 17, 'matching', 'mention of the cultural significance of wetlands', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'B');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (276, 1932, 18, 'fill_blank', 'Peatlands which have been drained begin to release ______ instead of storing it.', 'Peatlands which have been drained begin to release (18) ______ instead of storing it.\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (277, 1932, 19, 'fill_blank', 'Once peatland areas have been cleared, ______ are more likely to occur.', NULL, NULL, 'fires');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (278, 1932, 20, 'fill_blank', 'Clearing peatland forests to make way for oil palm plantations destroys the ______ of the local environment.', NULL, NULL, 'biodiversity');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (279, 1932, 21, 'fill_blank', 'Water is drained out of peatlands through the ______ which are created by logging companies.', NULL, NULL, 'ditches');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (280, 1932, 22, 'fill_blank', 'Draining peatlands leads to ______: a serious problem which can eventually result in coastal flooding and land loss.', NULL, NULL, 'subsidence');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (281, 1932, 23, 'matching', 'Communities living in wetland regions must be included in discussions about the future of these areas.', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'seemed to find the activity calming');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (282, 1932, 24, 'matching', 'Official policies towards wetlands vary from one nation to the next.', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'demonstrated independence');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (283, 1932, 25, 'matching', 'People cause harm to wetlands without having any intention to do so.', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'developed a competitive attitude');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (284, 1932, 26, 'matching', 'Initiatives to reverse environmental damage need not be complex.', NULL, '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'seemed to find the activity easy');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1933, 193, 3, 'Passage 3: Is the era of artificial speech translation upon us', 'Once the stuff of science fiction, technology that enables people to talk using different languages is now here. But how effective is it?\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (285, 1933, 27, 'multiple_choice', 'What does the reader learn about the conversation in the first paragraph?', NULL, '["A. The speakers are communicating in different languages","B. Neither of the speakers is familiar with their environment","C. The topic of the conversation is difficult for both speakers","D. Aspects of the conversation are challenging for both speakers"]', 'Aspects of the conversation are challenging for both speakers.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (286, 1933, 28, 'multiple_choice', 'What assists the electronic translator during lectures at Karlsruhe Institute of Technology?', NULL, '["A. the repeated content of lectures","B. the students\' reading skills","C. the languages used","D. the lecturers\' technical ability"]', 'the repeated content of lectures');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (287, 1933, 29, 'multiple_choice', 'When referring to The Hitchhiker\'s Guide to the Galaxy, the writer suggests that', NULL, '["A. the Babel fish was considered undesirable at the time","B. this book was not seriously intending to predict the future","C. artificial speech translation was not a surprising development","D. some speech translation techniques are better than others"]', 'artificial speech translation was not a surprising development.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (288, 1933, 30, 'multiple_choice', 'What does the writer say about sharing earpieces?', NULL, '["A. It is something people will get used to doing","B. The reluctance to do this is understandable","C. The equipment will be unnecessary in the future","D. It is something few people need to worry about"]', 'The reluctance to do this is understandable.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (289, 1933, 31, 'matching', 'Speech translation methods are developing fast in Japan', NULL, '["but there are concerns about  this.","as systems do not need to conform to standard practices.","but they are far from perfect.","despite the noise issues.","because translation is immediate.","and have an awareness of good manners."]', 'but they are far from perfect.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (290, 1933, 32, 'matching', 'TV interviews that use translation voice over methods are successful', NULL, '["but there are concerns about  this.","as systems do not need to conform to standard practices.","but they are far from perfect.","despite the noise issues.","because translation is immediate.","and have an awareness of good manners."]', 'because translation is immediate.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (291, 1933, 33, 'matching', 'Future translation systems should address people appropriately', NULL, '["but there are concerns about  this.","as systems do not need to conform to standard practices.","but they are far from perfect.","despite the noise issues.","because translation is immediate.","and have an awareness of good manners."]', 'and have an awareness of good manners.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (292, 1933, 34, 'matching', 'Users may be able to maintain their local customs', NULL, '["but there are concerns about  this.","as systems do not need to conform to standard practices.","but they are far from perfect.","despite the noise issues.","because translation is immediate.","and have an awareness of good manners."]', 'as systems do not need to conform to standard practices.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (293, 1933, 35, 'true_false', 'Language translation systems will be seen as very useful throughout the academic and professional worlds.', NULL, NULL, 'NO');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (294, 1933, 36, 'true_false', 'The overall value of automated translation to family life is yet to be shown.', NULL, NULL, 'YES');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (295, 1933, 37, 'true_false', 'Automated translation could make life more difficult for immigrant families.', NULL, NULL, 'NO');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (296, 1933, 38, 'true_false', 'Visual aspects of language translation are being considered by scientists.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (297, 1933, 39, 'true_false', 'International scientists have found English easier to translate into otherlanguages than Latin.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (298, 1933, 40, 'true_false', 'As far as language is concerned, there is a difference between people\'s social and practical needs.', NULL, NULL, 'YES');
INSERT INTO IELTSExam (id, title, type, totalQuestions) VALUES (194, '剑桥雅思 19 - Test 4 阅读', 'reading', 40);
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1941, 194, 1, 'Passage 1: The impact of climate change on butterflies in Britain', 'According to conservationists, populations of around two thirds of butterfly species have declined in Britain over the past 40 years. If this trend continues, it might have unpredictable knock-on effects for other species in the ecosystem. Butterfly eggs develop into caterpillars and these insects, which are the second stage in a new butterfly\'s lifecycle, consume vast quantities of plant material, and in turn act as prey for birds as well as bats and other small mammals. Only by arming themselves with an understanding of why butterfly numbers are down can conservationists hope to halt or reverse the decline.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (299, 1941, 1, 'true_false', 'Forty years ago, there were fewer butterflies in Britain than at present.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (300, 1941, 2, 'true_false', 'Caterpillars are eaten by a number of different predators.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (301, 1941, 3, 'true_false', '\'Phenology\' is a term used to describe a creature\'s ability to alter the location of a lifecycle event.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (302, 1941, 4, 'true_false', 'Some species of butterfly have a reduced lifespan due to spring temperature increases.', NULL, NULL, 'NOT GIVEN');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (303, 1941, 5, 'true_false', 'There is a clear reason for the adaptations that butterflies are making to climate change.', NULL, NULL, 'FALSE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (304, 1941, 6, 'true_false', 'The data used in the study was taken from the work of amateur butterfly watchers.', NULL, NULL, 'TRUE');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (305, 1941, 7, 'fill_blank', '● The new cities were dirty, crowded and lacked sufficient ______ .', '## Butterflies in the UK\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (306, 1941, 8, 'fill_blank', '·Mike and Bob Bryan made changes to the types of ______ used on their racket frames.', NULL, NULL, 'spring');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (307, 1941, 9, 'fill_blank', '·Players were not allowed to use the spaghetti-strung racket because of the amount of ______ it created.', NULL, NULL, 'endangered');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (308, 1941, 10, 'fill_blank', '·Changes to rackets can be regarded as being as important as players\' diets or the ______ they do.', NULL, NULL, 'habitat|habitats');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (309, 1941, 11, 'fill_blank', '·All rackets used to have natural strings made from the ______ of animals.', NULL, NULL, 'Europe');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (310, 1941, 12, 'fill_blank', '·Pete Sampras had metal ______ put into the frames of his rackets.', NULL, NULL, 'southern');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (311, 1941, 13, 'fill_blank', '·Gonçalo Oliveira changed the ______ on his racket handles.', NULL, NULL, 'diet');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1942, 194, 2, 'Passage 2: Deep-sea mining', 'A\nWhen Professor Mat Upton found that a microbe from a deep-sea sponge was killing pathogenic bugs in his laboratory, he realised it could be a breakthrough in the fight against antibiotic-resistant superbugs, which are responsible for thousands of deaths a year in the UK alone. Further tests confirmed that an antibiotic from the sponge bacteria, found living more than 700 metres under the sea at the Rockall trough in the north-east Atlantic, was previously unknown to science, boosting its potential as a life-saving medicine. But Upton, and other scientists who view the deep ocean and its wealth of unique and undocumented species as a prospecting ground for new medicines, fear such potential will be lost in the rush to exploit the deep sea\'s equally rich metal and mineral resources.\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (312, 1942, 14, 'matching', 'reference to the rapidly increasing need for one raw material in the transport industry', NULL, '["A","B","C","D","E","F"]', 'C');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (313, 1942, 15, 'matching', 'a rough estimate of the area of the Earth covered by the oceans', NULL, '["A","B","C","D","E","F"]', 'F');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (314, 1942, 16, 'matching', 'how a particular underwater habitat, where minerals and organisms co-exist, is formed', NULL, '["A","B","C","D","E","F"]', 'E');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (315, 1942, 17, 'matching', 'reference to the fact that the countries of the world have yet to agree on rules for the exploration of the seabed', NULL, '["A","B","C","D","E","F"]', 'D');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (316, 1942, 18, 'matching', 'A move away from the exploration of heavily mined reserves on land is a good idea. ______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Mike Johnston');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (317, 1942, 19, 'matching', 'The negative effects of undersea exploration on local areas and their inhabitants are being ignored. ______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Julie Hunter, Julian Aguon and Pradeep Singh');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (318, 1942, 20, 'matching', 'There are more worthwhile things to extract from the sea than minerals. ______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Professor Mat Upton');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (319, 1942, 21, 'matching', 'No other form of human exploration will have such a destructive impact on marine life as deep-sea mining.______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Verena Tunnicliffe');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (320, 1942, 22, 'matching', 'More is known about outer space than about what lies beneath the oceans.______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Julie Hunter, Julian Aguon and Pradeep Singh');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (321, 1942, 23, 'matching', 'There is one marine life habitat where experts agree mining should not take place. ______', NULL, '["Professor Mat Upton","Julie Hunter, Julian Aguon and Pradeep Singh","Dr Jon Copley","Mike Johnston","Verena Tunnicliffe"]', 'Dr Jon Copley');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (322, 1942, 24, 'fill_blank', 'Mining corporations believe that the mineral resources lying under the sea may be superior to those found in the earth. They also say that these can be removed without producing much ______.', '## Mining the sea floor\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (323, 1942, 25, 'fill_blank', 'The extraction is often done by adapting the ______', NULL, NULL, 'machinery');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (324, 1942, 26, 'fill_blank', 'that has already been used to work on land. The method of excavation involves removing the seawater from the slurry that is brought up to ships and returning it to the seabed. However, concerned groups strongly believe that ______ is necessary due to the possible number of unidentified consequences.', NULL, NULL, 'caution');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (1943, 194, 3, 'Passage 3: The Unselfish Gene', 'A psychologist gives his view on how humans became self-centred\n\nINSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (325, 1943, 27, 'multiple_choice', 'What is the writer doing in the first paragraph?', NULL, '["To celebrate Dawkins\' achievement","To define key biological terms","To present a widely accepted theory in order to challenge it","To argue that cooperation is more important than competition"]', 'describing a commonly held belief about people\'s behaviour');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (326, 1943, 28, 'multiple_choice', 'What point is made about Richard Dawkins\' book The Selfish Gene?', NULL, '["It was universally accepted","It was immediately controversial","It may have overstated the case for competition","It focused mainly on cooperation"]', 'It presented a view that was in line with the attitudes of its time.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (327, 1943, 29, 'multiple_choice', 'What does the writer suggest about the prehistoric era in the fourth paragraph?', NULL, '["People lived in constant fear","Fierce competition was not necessarily the norm","There was no cooperation at all","Only the strongest survived"]', 'Supplies of natural resources were probably relatively plentiful.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (328, 1943, 30, 'multiple_choice', 'The writer refers to Bruce Knauft\'s work as support for the idea that', NULL, '["Hunter-gatherers exhibit high egalitarianism","Competition drove human evolution","Men dominated prehistoric societies","Agriculture ended cooperation"]', 'selfishness is a relatively recent development in human societies.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (329, 1943, 31, 'fill_blank', 'Bruce Knauft\'s research shows that contemporary hunter-gatherer societies tend to exhibit a high level of ______ in all areas of life. In these cultures, distributing resources fairly among all members is a moral obligation. These societies also employ strategies to prevent differences in ______ occurring: for example, the !Kung follow a custom whereby the credit for one person\'s success at ______ is given to another member of the group. Individuals who behave in a ______ manner are punished by being excluded from the group, and women have a considerable amount of ______ in choices regarding work and marriage.', '## Contemporary hunter-gatherer societies\n\nBruce Knauft\'s research shows that contemporary hunter-gatherer societies tend to exhibit a high level of (31) ______ in all areas of life. In these cultures, distributing resources fairly among all members is a moral obligation. These societies also employ strategies to prevent differences in (32) ______ occurring: for example, the !Kung follow a custom whereby the credit for one person\'s success at (33) ______ is given to another member of the group. Individuals who behave in a (34) ______ manner are punished by being excluded from the group, and women have a considerable amount of  (35) ______ in choices regarding work and marriage.', NULL, 'egalitarianism');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (330, 1943, 32, 'fill_blank', 'Bruce Knauft\'s research shows that contemporary hunter-gatherer societies tend to exhibit a high level of ______ in all areas of life. In these cultures, distributing resources fairly among all members is a moral obligation. These societies also employ strategies to prevent differences in ______ occurring: for example, the !Kung follow a custom whereby the credit for one person\'s success at ______ is given to another member of the group. Individuals who behave in a ______ manner are punished by being excluded from the group, and women have a considerable amount of ______ in choices regarding work and marriage.', NULL, NULL, 'status');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (331, 1943, 33, 'fill_blank', 'Bruce Knauft\'s research shows that contemporary hunter-gatherer societies tend to exhibit a high level of ______ in all areas of life. In these cultures, distributing resources fairly among all members is a moral obligation. These societies also employ strategies to prevent differences in ______ occurring: for example, the !Kung follow a custom whereby the credit for one person\'s success at ______ is given to another member of the group. Individuals who behave in a ______ manner are punished by being excluded from the group, and women have a considerable amount of ______ in choices regarding work and marriage.', NULL, NULL, 'hunting');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (332, 1943, 34, 'fill_blank', 'Bruce Knauft\'s research shows that contemporary hunter-gatherer societies tend to exhibit a high level of ______ in all areas of life. In these cultures, distributing resources fairly among all members is a moral obligation. These societies also employ strategies to prevent differences in ______ occurring: for example, the !Kung follow a custom whereby the credit for one person\'s success at ______ is given to another member of the group. Individuals who behave in a ______ manner are punished by being excluded from the group, and women have a considerable amount of ______ in choices regarding work and marriage.', NULL, NULL, 'domineering');
