INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004591, 19013, 23, 'multiple_choice', 'Which **TWO** ways do the students agree that touch-sensitive sensors for food labels could be developed in future?', NULL, '["A. for use on medical products","B. to show that food is no longer fit to eat","C. for use with drinks as well as foods","D. to provide applications for blind people","E. to indicate the weight of certain foods"]', 'A. for use on medical products');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004592, 19013, 24, 'multiple_choice', 'Which **TWO** ways do the students agree that touch-sensitive sensors for food labels could be developed in future?', NULL, '["A. for use on medical products","B. to show that food is no longer fit to eat","C. for use with drinks as well as foods","D. to provide applications for blind people","E. to indicate the weight of certain foods"]', 'E. to indicate the weight of certain foods');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004593, 19013, 25, 'matching', 'Use of local products', NULL, '["This is only relevant to young people.","This may have disappointing results.","This already seems to be widespread.","Retailers should do more to encourage this.","More financial support is needed for this.","Most people know little about this.","There should be stricter regulations about this.","This could be dangerous."]', 'Retailers should do more to encourage this.');
