INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004599, 19014, 31, 'fill_blank', NULL, '[note]\n# Céide Fields\n\n## an important Neolithic archaeological site in the northwest of Ireland\n\n## Discovery\n· In the 1930s, a local teacher realised that stones beneath the bog surface were once {Q31}\n· His {Q32} became an archaeologist and undertook an investigation of the site\n· a traditional method used by local people to dig for {Q33} was used to identify where stones were located\n· carbon dating later proved the site was Neolithic.\n· Items are well preserved in the bog because of a lack of {Q34}\n\n## Neolithic farmers\n· Houses were {Q35} in shape and had a hole in the roof.\n· Neolithic innovations include:\n- cooking indoors\n- pots used for storage and to make {Q36}.\n· Each field at Céide was large enough to support a big {Q37}.\n· The fields were probably used to restrict the movement of grazing animals\n\n## Decline\n· a decrease in {Q38} temperatures led to the formation of blanket bog\n· the bog covered the land and the {Q39} became less fertile\n· this meant the land could no longer support the same number of people\n· the community declined due to the increased frequency of {Q40}', NULL, 'walls');
