INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004619, 19022, 11, 'multiple_choice', 'What made David leave London and move to Northsea?', NULL, '["A. He was eager to develop a hobby.","B. He wanted to work shorter hours.","C. He found his job in website design unsatisfying."]', 'A. He was eager to develop a hobby.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004620, 19022, 12, 'multiple_choice', 'The Lifeboat Institution in Northsea was built with money provided by', NULL, '["A. a local organisation.","B. a local resident.","C. the local council."]', 'A. a local organisation.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004621, 19022, 13, 'multiple_choice', 'In his health assessment, the doctor was concerned about the fact that David', NULL, '["A. might be colour blind.","B. was rather short-sighted.","C. had undergone eye surgery."]', 'A. might be colour blind.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004622, 19022, 14, 'multiple_choice', 'After arriving at the lifeboat station, they aim to launch the boat within', NULL, '["A. five minutes.","B. six to eight minutes.","C. eight and a half minutes."]', 'A. five minutes.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004623, 19022, 15, 'multiple_choice', 'As a \'helmsman\', David has the responsibility of deciding', NULL, '["A. who will be the members of his crew.","B. what equipment it will be necessary to take.","C. if the lifeboat should be launched."]', 'A. who will be the members of his crew.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004624, 19022, 16, 'multiple_choice', 'As well as going out on the lifeboat, David', NULL, '["A. gives talks on safety at sea.","B. helps with fundraising.","C. recruits new volunteers."]', 'A. gives talks on safety at sea.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004625, 19022, 17, 'multiple_choice', 'Which **TWO** things does David say about the lifeboat volunteer training?', NULL, '["A. The residential course developed his leadership skills.","B. The training in use of ropes and knots was quite brief.","C. The training exercises have built up his mental strength.","D. The casualty care activities were particularly challenging for him.","E. The wave tank activities provided practice in survival techniques."]', 'C. The training exercises have built up his mental strength.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004626, 19022, 18, 'multiple_choice', 'Which **TWO** things does David say about the lifeboat volunteer training?', NULL, '["A. The residential course developed his leadership skills.","B. The training in use of ropes and knots was quite brief.","C. The training exercises have built up his mental strength.","D. The casualty care activities were particularly challenging for him.","E. The wave tank activities provided practice in survival techniques."]', 'E. The wave tank activities provided practice in survival techniques.');
