INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004639, 19024, 31, 'fill_blank', NULL, '[note]\n# Tidal power\n\n## Advantages\n● {Q31} of water are used to spin turbines\n● relatively {Q32} lifespan of equipment\n● does not involve the burning of {Q33} or fossil fuels\n● minimal {Q34} needed once installed\n\n## How it works\n● water passes through a {Q35} which is a narrow channel\n● the force of the water spins turbines\n● these turbines are designed to work at low {Q36}\n● the power generated can be predicted accurately\n\n## Environmental impact\n● can affect {Q37} in fish and other marine life\n● fish are able to pass through the system safely\n● turbines do not harm {Q38} as they pass through\n\n## Future developments\n● could be combined with {Q39} farms\n● potential to power many homes\n● may help protect {Q40} species by reducing reliance on fossil fuels', NULL, 'move');
