INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004674, 19033, 26, 'matching', 'Choose mice which are all the same', '[flowchart]\n## Step\nChoose mice which are all the same {Q26}.\n\n## Step\nDivide the mice into two groups, each with a different {Q27}.\n\n## Step\nPut each group in a separate cage.\nFeed group A commercial mouse food.\nFeed group B the same, but also sugar contained in {Q28}.\n\n## Step\nTake measurements using an electronic scale.\nPlace them in a weighing chamber to prevent {Q29}.\n\n## Step\nDo all necessary {Q30}.', '["size","escape","age","water","cereal","calculations","changes","colour"]', 'age');
