INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004699, 19042, 11, 'multiple_choice', 'Which **TWO** problems with some training programmes for new runners does Liz mention?', NULL, '["A. There is a risk of serious injury.","B. They are unsuitable for certain age groups.","C. They are unsuitable for people with health issues.","D. It is difficult to stay motivated.","E. There is a lack of individual support."]', 'A. There is a risk of serious injury.');
