INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004701, 19042, 13, 'multiple_choice', 'Which **TWO** tips does Liz recommend for new runners?', NULL, '["A. doing two runs a week","B. running in the evening","C. going on runs with a friend","D. listening to music during runs","E. running very slowly"]', 'A. doing two runs a week');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004702, 19042, 14, 'multiple_choice', '(second)', NULL, '["A. doing two runs a week","B. running in the evening","C. going on runs with a friend","D. listening to music during runs","E. running very slowly"]', 'D. listening to music during runs');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004703, 19042, 15, 'matching', 'Ceri', NULL, '["a lack of confidence","a dislike of running","a lack of time"]', 'a lack of confidence');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004704, 19042, 16, 'matching', 'James', NULL, '["a lack of confidence","a dislike of running","a lack of time"]', 'a dislike of running');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004705, 19042, 17, 'matching', 'Leo', NULL, '["a lack of confidence","a dislike of running","a lack of time"]', 'a lack of time');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004706, 19042, 18, 'matching', 'Mark', NULL, '["a lack of confidence","a dislike of running","a lack of time"]', 'a lack of confidence');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004707, 19042, 19, 'multiple_choice', 'What does Liz say about running her first marathon?', NULL, '["A. It had always been her ambition","B. Her husband persuaded her to do it","C. She nearly gave up before the end"]', 'It had always been her ambition.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004708, 19042, 20, 'multiple_choice', 'Liz says new runners should sign up for a race', NULL, '["A. every six months","B. within a few weeks of taking up running","C. after completing several practice runs"]', 'every six months.');
INSERT INTO IELTSExamSection (id, examId, sectionIndex, title, instructions, audioUrl, imageUrl) VALUES (19043, 1904, 3, 'Part 3', 'Choose the correct letter, A, B or C .\n\nWhere does Jane’s grandfather keep each of the following types of books in his shop? Choose FIVE answers from the box and write the correct letter, A–G, next to Questions 26–30.', 'https://yxzm-audio.oss-cn-beijing.aliyuncs.com/Cambridge-IELTS-19/T4/S3.mp3', NULL);
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004709, 19043, 21, 'multiple_choice', 'What do both students agree about the advice given to people clearing out their books?', NULL, '["A. common sense.","B. hard to follow.","C. over-protective."]', 'A. common sense.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004710, 19043, 22, 'multiple_choice', 'Jane and Kieran agree that hardback books should be', NULL, '["A. They are not worth keeping.","B. They should go to a collector.","C. They have sentimental value for her."]', 'A. They are not worth keeping.');
INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004711, 19043, 23, 'multiple_choice', 'What does Kieran suggest should happen to old encyclopedias?', NULL, '["A. put out on display.","B. given as gifts to visitors.","C. more attractively designed."]', 'A. put out on display.');
