INSERT INTO IELTSQuestion (id, sectionId, questionIndex, questionType, questionText, passageText, options, correctAnswer) VALUES (2004713, 19043, 25, 'multiple_choice', 'What do Jane and Kieran suggest about new books?', NULL, '["A. Their parents liked buying them as presents.","B. They would like to buy more of them.","C. Not everyone can afford them."]', 'A. Their parents liked buying them as presents.');
